const payload = $json.body ?? $json;
const normalize = (value) => String(value ?? '').trim();
const digitsOnly = (value) => normalize(value).replace(/\D/g, '');
const allUserText = (payload.messages ?? [])
  .filter((message) => message.role === 'user')
  .map((message) => String(message.content ?? ''))
  .join(' ');
const latestUserMessage = [...(payload.messages ?? [])].reverse().find((message) => message.role === 'user')?.content ?? '';
const extractedPhone = allUserText.match(/(?:\+\d{7,15}|(?:\+?66|0)\d[\d\s-]{7,})/)?.[0] ?? '';
const extractedEmail = allUserText.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i)?.[0] ?? '';
const extractedName = allUserText.match(/(?:my name is|name is|i am|i'm)\s+([A-Za-z][A-Za-z\s'-]{1,40})/i)?.[1]?.trim() ?? '';
const preferredContact = normalize(payload.lead?.preferredContact) || (extractedPhone ? 'phone' : extractedEmail ? 'email' : '');
const notes = normalize(payload.lead?.notes);
const lead = {
  name: normalize(payload.name ?? payload.lead?.name) || extractedName,
  phone: normalize(payload.phone ?? payload.lead?.phone) || normalize(extractedPhone),
  email: normalize(payload.email ?? payload.lead?.email) || normalize(extractedEmail),
  message: normalize(payload.message || latestUserMessage || payload.handover?.summary),
  budget: normalize(payload.budget),
  area: normalize(payload.area),
  preferredContact,
  notes,
};
const fallbackFlags = [];
if (!lead.phone && !lead.email) fallbackFlags.push('missing_contact');
if (lead.message.length < 8) fallbackFlags.push('message_too_short');
if (/^(test|tester|admin|fake|unknown|n\/a)$/i.test(lead.name)) fallbackFlags.push('fake_name');
if (/^(test|fake|demo|sample)/i.test(lead.email)) fallbackFlags.push('fake_email');
if (digitsOnly(lead.phone) && /^(0|1|9)\1+$/.test(digitsOnly(lead.phone))) fallbackFlags.push('fake_phone');
if (/free money|casino|crypto|seo service|loan|https?:\/\//i.test(Object.values(lead).join(' '))) fallbackFlags.push('spam_pattern');
let validation = {
  valid: fallbackFlags.length === 0,
  reason: fallbackFlags[0] ?? null,
  flags: fallbackFlags
};
if ($env.OPENAI_API_KEY) {
  try {
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${$env.OPENAI_API_KEY}`
      },
      body: JSON.stringify({
        model: 'gpt-5.4-mini',
        temperature: 0,
        response_format: { type: 'json_object' },
        messages: [
          {
            role: 'system',
            content: 'You validate inbound sales leads. Return strict JSON only: {"valid":boolean,"reason":string|null,"flags":[string]}. Reject spam, empty leads, fake-looking names/contact details, nonsense, or entries without any usable contact method. Do not reject just because optional budget or area is missing.'
          },
          {
            role: 'user',
            content: JSON.stringify({ lead, handover: payload.handover ?? null })
          }
        ]
      })
    });
    if (response.ok) {
      const data = await response.json();
      const parsed = JSON.parse(data.choices?.[0]?.message?.content ?? '{}');
      if (typeof parsed.valid === 'boolean') {
        validation = {
          valid: parsed.valid,
          reason: parsed.reason ?? (parsed.valid ? null : 'ai_rejected'),
          flags: Array.isArray(parsed.flags) ? parsed.flags.map(String) : fallbackFlags
        };
      }
    }
  } catch (error) {
    validation.flags = [...new Set([...validation.flags, 'ai_validation_fallback'])];
  }
}
return [{ json: { ...payload, ...lead, validation } }];

const baseUrl = $env.GRASPIA_APP_BASE_URL || 'http://host.docker.internal:3000';
const storage = { databaseSaved: false, databaseError: null };
const preliminaryAutomation = {
  accepted: Boolean($json.validation?.valid),
  rejected: !Boolean($json.validation?.valid),
  tier: 'cold',
  reasoning: $json.validation?.valid ? 'Lead received and stored before classification.' : `Lead rejected during validation: ${$json.validation?.reason ?? 'unknown'}`,
  autoReply: '',
  notifyUrgent: false,
  notificationSent: false,
  notificationChannel: 'not-classified-yet',
  validationReason: $json.validation?.reason ?? null
};
try {
  const response = await fetch(`${baseUrl}/api/automation/lead`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      conversationId: $json.conversationId,
      preferredLanguage: $json.preferredLanguage ?? 'en',
      name: $json.name ?? '',
      phone: $json.phone ?? '',
      email: $json.email ?? '',
      message: $json.message ?? '',
      budget: $json.budget ?? '',
      area: $json.area ?? '',
      handover: $json.handover ?? null,
      automation: preliminaryAutomation,
      rawPayload: $json
    })
  });
  if (response.ok) {
    const saved = await response.json();
    storage.databaseSaved = true;
    storage.leadRecordId = saved.leadRecordId ?? null;
  } else {
    storage.databaseError = `${response.status} ${await response.text()}`;
  }
} catch (error) {
  storage.databaseError = error instanceof Error ? error.message : String(error);
}
return [{ json: { ...$json, storage } }];

const payload = $('AI Validate Lead').first().json;
const storage = $('Save Lead to Database Best Effort').first().json.storage ?? {};
const preferredLanguage = payload.preferredLanguage === 'th' ? 'th' : 'en';
const invalid = !payload.validation?.valid;
let classification = invalid
  ? {
      tier: 'cold',
      reasoning: `Lead rejected during validation: ${payload.validation?.reason ?? 'invalid'}`,
      autoReply: ''
    }
  : null;
if (!classification && $env.OPENAI_API_KEY) {
  try {
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${$env.OPENAI_API_KEY}`
      },
      body: JSON.stringify({
        model: 'gpt-5.4-mini',
        temperature: 0.2,
        response_format: { type: 'json_object' },
        messages: [
          {
            role: 'system',
            content: 'You classify validated inbound solar leads. Return strict JSON only: {"tier":"hot|warm|cold","reasoning":"..."}. Base tier on message, budget, area, buying urgency, frustration, and handover reason. hot means immediate team notification is needed. warm/cold should not trigger urgent notification.'
          },
          {
            role: 'user',
            content: JSON.stringify({
              preferredLanguage,
              lead: {
                name: payload.name,
                phone: payload.phone,
                email: payload.email,
                message: payload.message,
                budget: payload.budget,
                area: payload.area
              },
              handover: payload.handover ?? null
            })
          }
        ]
      })
    });
    if (response.ok) {
      const data = await response.json();
      const parsed = JSON.parse(data.choices?.[0]?.message?.content ?? '{}');
      if (['hot', 'warm', 'cold'].includes(parsed.tier) && typeof parsed.reasoning === 'string') {
        classification = {
          tier: parsed.tier,
          reasoning: parsed.reasoning,
          autoReply: ''
        };
      }
    }
  } catch (error) {
    // Fallback below keeps the workflow moving.
  }
}
if (!classification) {
  const text = `${payload.message} ${payload.budget} ${payload.handover?.summary ?? ''}`.toLowerCase();
  const isHot = payload.handover?.reason === 'ready_to_buy' || payload.handover?.reason === 'angry_client' || /ready|buy|purchase|sign|pay|deposit|invoice/.test(text);
  const isWarm = payload.handover?.reason === 'asked_for_human' || /\d/.test(payload.budget ?? '') || /survey|quote|interested/.test(text);
  classification = {
    tier: isHot ? 'hot' : isWarm ? 'warm' : 'cold',
    reasoning: isHot
      ? 'Fallback scoring marked this lead as urgent based on close intent or frustration.'
      : isWarm
        ? 'Fallback scoring found interest or budget signal, but no immediate close intent.'
        : 'Fallback scoring found limited buying signal and more qualification is needed.',
    autoReply: ''
  };
}
let autoReply = classification.autoReply;
if ($env.OPENAI_API_KEY) {
  try {
    const replyResponse = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${$env.OPENAI_API_KEY}`
      },
      body: JSON.stringify({
        model: 'gpt-5.4-mini',
        temperature: 0.4,
        response_format: { type: 'json_object' },
        messages: [
          {
            role: 'system',
            content: 'You write a short customer-facing acknowledgement for a solar lead. Return strict JSON only: {"autoReply":"..."}. Keep it warm, natural, and specific to the conversation. If the lead is incomplete, say the details are not enough yet but the team will reach out soon to ask for the missing information. If the lead is valid, acknowledge interest and mention next steps. Do not mention internal validation errors. Match the preferred language. Avoid sounding robotic or canned.'
          },
          {
            role: 'user',
            content: JSON.stringify({
              preferredLanguage,
              validation: payload.validation ?? null,
              classification: {
                tier: classification.tier,
                reasoning: classification.reasoning
              },
              lead: {
                name: payload.name,
                phone: payload.phone,
                email: payload.email,
                message: payload.message,
                budget: payload.budget,
                area: payload.area
              },
              handover: payload.handover ?? null,
              business: payload.business ?? null
            })
          }
        ]
      })
    });
    if (replyResponse.ok) {
      const replyData = await replyResponse.json();
      const replyParsed = JSON.parse(replyData.choices?.[0]?.message?.content ?? '{}');
      if (typeof replyParsed.autoReply === 'string' && replyParsed.autoReply.trim()) {
        autoReply = replyParsed.autoReply.trim();
      }
    }
  } catch (error) {
    // Use the fallback auto reply below.
  }
}
if (!autoReply) {
  autoReply = invalid
    ? 'Thanks for reaching out. We do not have enough details yet, but our team will contact you soon to ask for the missing information and help with the next step.'
    : 'Thanks for the details. Our team will review everything and follow up soon with the next step.';
}
const automation = {
  accepted: Boolean(payload.validation?.valid),
  rejected: !Boolean(payload.validation?.valid),
  tier: classification.tier,
  reasoning: classification.reasoning,
  autoReply,
  notifyUrgent: classification.tier === 'hot' && Boolean(payload.validation?.valid),
  notificationSent: false,
  notificationChannel: classification.tier === 'hot' && Boolean(payload.validation?.valid) ? 'telegram-pending' : 'saved-only',
  validationReason: payload.validation?.reason ?? null,
  leadRecordId: storage.leadRecordId ?? null,
  storage: {
    databaseSaved: Boolean(storage.databaseSaved),
    databaseError: storage.databaseError ?? null
  }
};
return [{ json: { ...payload, storage, automation } }];

