const original = $('AI Classify Lead').first().json;
const notificationFailed = Boolean($json.error || $json.message || $json.statusCode >= 400 || $json.ok === false);
return [{
  json: {
    ...original.automation,
    notificationSent: !notificationFailed,
    notificationChannel: notificationFailed ? 'telegram-failed' : 'telegram',
    notificationError: notificationFailed ? ($json.description ?? $json.error?.message ?? $json.message ?? JSON.stringify($json)) : null
  }
}];
